@using Microsoft.AspNetCore.Components
@inject NavigationManager Navigation

@code {
    protected override void OnInitialized()
    {
        var returnUrl = Uri.EscapeDataString(Navigation.ToBaseRelativePath(Navigation.Uri));
        Navigation.NavigateTo($"Account/Login?returnUrl=/{returnUrl}", forceLoad: true);
    }
}

@page "/Account/Login"
@using Microsoft.AspNetCore.Identity
@using sv_1800f352be6f449dbcbe839f1c92bd1a.Data
@inject SignInManager<ApplicationUser> SignInManager
@inject NavigationManager Navigation

<PageTitle>Login</PageTitle>

<div class="row justify-content-center mt-5">
    <div class="col-md-4">
        <h3>Login</h3>
        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }
        <form method="post" @formname="login">
            <AntiforgeryToken />
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" name="email" class="form-control" @bind-value="email" required />
            </div>
            <div class="mb-3">
                <label class="form-label">Password</label>
                <input type="password" name="password" class="form-control" @bind-value="password" required />
            </div>
            <input type="hidden" name="returnUrl" value="@returnUrl" />
            <button type="submit" class="btn btn-primary w-100">Sign in</button>
        </form>
    </div>
</div>

@code {
    [SupplyParameterFromForm] private string email { get; set; } = "";
    [SupplyParameterFromForm] private string password { get; set; } = "";
    [SupplyParameterFromQuery] private string? returnUrl { get; set; }
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        if (HttpMethods.IsPost(HttpContextAccessor.HttpContext!.Request.Method))
        {
            var result = await SignInManager.PasswordSignInAsync(email, password, isPersistent: false, lockoutOnFailure: false);
            if (result.Succeeded)
            {
                Navigation.NavigateTo(returnUrl ?? "/", forceLoad: true);
            }
            else
            {
                errorMessage = "Invalid email or password.";
            }
        }
    }

    [CascadingParameter] public HttpContext HttpContextAccessor { get; set; } = default!;
}

@page "/Account/Logout"
@using Microsoft.AspNetCore.Identity
@using sv_1800f352be6f449dbcbe839f1c92bd1a.Data
@inject SignInManager<ApplicationUser> SignInManager
@inject NavigationManager Navigation

@code {
    [CascadingParameter] public HttpContext HttpContext { get; set; } = default!;

    protected override async Task OnInitializedAsync()
    {
        await SignInManager.SignOutAsync();
        Navigation.NavigateTo("/", forceLoad: true);
    }
}

@page "/admin/users"
@attribute [Authorize(Roles = "Admin")]
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Identity
@using sv_1800f352be6f449dbcbe839f1c92bd1a.Data
@inject UserManager<ApplicationUser> UserManager

<PageTitle>User Management</PageTitle>

<h1>User Management</h1>
<p>Manage all users and their assigned roles.</p>

@if (users is null)
{
    <p><em>Loading users...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Name</th>
                <th>Email</th>
                <th>Roles</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var u in users)
            {
                <tr>
                    <td>@u.FullName</td>
                    <td>@u.Email</td>
                    <td>@string.Join(", ", u.Roles)</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<UserWithRoles>? users;

    protected override async Task OnInitializedAsync()
    {
        var allUsers = UserManager.Users.ToList();
        var list = new List<UserWithRoles>();
        foreach (var user in allUsers)
        {
            var roles = await UserManager.GetRolesAsync(user);
            list.Add(new UserWithRoles(user.FullName, user.Email!, roles));
        }
        users = list;
    }

    private record UserWithRoles(string FullName, string Email, IList<string> Roles);
}

